# Service for integrating with ComfyUI API for stock photo extraction
# ComfyUI is a node-based Stable Diffusion UI that supports image editing
class ComfyUiService
  def self.base_url
    ENV["COMFY_UI_API_URL"] || "http://localhost:8188"
  end

  class << self
    # Extract stock photo from original image using ComfyUI + Qwen Image Edit
    # @param original_image_blob [ActiveStorage::Blob] The original image blob
    # @param extraction_prompt [String] The extraction prompt generated by ExtractionPromptBuilder
    # @return [Hash] Result containing extracted image data or error
    def extract_stock_photo(original_image_blob:, extraction_prompt:)
      Rails.logger.info "Starting ComfyUI stock photo extraction"

      # Validate inputs
      unless original_image_blob.present?
        raise ArgumentError, "Original image blob is required"
      end

      unless extraction_prompt.present?
        raise ArgumentError, "Extraction prompt is required"
      end

      # Check ComfyUI availability
      check_comfyui_availability!

      # Upload image to ComfyUI and get filename
      image_filename = upload_image(original_image_blob)

      # Build workflow payload using actual workflow template
      workflow_data = build_workflow(image_filename, extraction_prompt)

      # Generate client_id for WebSocket tracking (must match between submission and WebSocket)
      client_id = SecureRandom.uuid

      # Submit to ComfyUI with client_id for WebSocket tracking
      job_id = submit_workflow(workflow_data, client_id: client_id)

      # Try WebSocket first for real-time completion, fallback to polling
      begin
        result = wait_for_completion_via_websocket(job_id, client_id: client_id)
        Rails.logger.info "ComfyUI extraction completed via WebSocket (job: #{job_id})"
        result
      rescue StandardError => ws_error
        Rails.logger.warn "WebSocket completion failed: #{ws_error.message}. Falling back to polling..."
        # Fallback to polling
        result = poll_for_completion(job_id)
        Rails.logger.info "ComfyUI extraction completed via polling (job: #{job_id})"
        result
      end
    rescue ArgumentError => e
      # Re-raise ArgumentError - these are validation errors that callers should handle
      raise
    rescue StandardError => e
      Rails.logger.error "ComfyUI extraction failed: #{e.message}"
      Rails.logger.error e.backtrace.first(10).join("\n")
      { "error" => e.message, "success" => false }
    end

    # Handle WebSocket messages from ComfyUI
    # Public method so it can be called from WebSocket callback blocks
    def handle_websocket_message(message, job_id)
      return unless message.is_a?(Hash)

      case message["type"]
      when "executing"
        data = message["data"]
        if data && data["node"].nil? && data["prompt_id"] == job_id
          # Execution complete - fetch results
          Rails.logger.info "ComfyUI job completed via WebSocket (prompt_id: #{job_id})"
          result = fetch_job_results_after_completion(job_id)
          yield(result) if result && block_given?
        end
      when "progress"
        # Progress updates - log for debugging
        progress_data = message["data"]
        Rails.logger.debug "ComfyUI progress: #{progress_data.inspect}"
      when "execution_error"
        error_data = message["data"]
        error_msg = error_data["error_message"] || error_data["message"] || "Unknown error"
        Rails.logger.error "ComfyUI execution error: #{error_msg}"
        raise StandardError, "ComfyUI execution error: #{error_msg}"
      when "execution_start"
        # Job started executing
        Rails.logger.debug "ComfyUI job started executing"
      when "execution_cached"
      # Node output was cached
      Rails.logger.debug "ComfyUI node output cached"
      end
  end

  # Fetch job results after WebSocket completion notification
  # Public method so it can be called from WebSocket callback blocks
  def fetch_job_results_after_completion(job_id)
    base_uri = URI(base_url)
    http = Net::HTTP.new(base_uri.host, base_uri.port)
    http.open_timeout = 10
    http.read_timeout = 30

    # Get history
    request = Net::HTTP::Get.new("/history/#{job_id}")
    response = http.request(request)

    unless response.code == "200"
      raise StandardError, "Failed to fetch ComfyUI history: HTTP #{response.code}"
    end

    result = JSON.parse(response.body)
    job_data = result[job_id]

    unless job_data && job_data.is_a?(Hash)
      raise StandardError, "ComfyUI history does not contain job data for #{job_id}"
    end

    outputs = job_data["outputs"] || {}
    status = job_data["status"]

    # Check if job failed
    if status && status["status_str"] == "error"
      error_msg = if status["messages"] && status["messages"].any?
        status["messages"].join("; ")
      else
        "Unknown error"
      end
      raise StandardError, "ComfyUI job failed: #{error_msg}"
    end

    # Extract image data
    image_data = extract_image_from_outputs(outputs, http, base_uri)

    unless image_data
      raise StandardError, "ComfyUI did not return image data"
    end

    image_size = image_data.respond_to?(:bytesize) ? image_data.bytesize : image_data.size
    Rails.logger.info "ComfyUI returned image data: #{image_size} bytes (#{(image_size / 1024.0).round(2)} KB)"

    {
      "success" => true,
      "job_id" => job_id,
      "outputs" => outputs,
      "image_data" => image_data
    }
  rescue JSON::ParserError => e
    Rails.logger.error "Failed to parse ComfyUI history response: #{e.message}"
    raise StandardError, "Invalid JSON from ComfyUI history endpoint"
  end

  private

    def check_comfyui_availability!
      base_uri = URI(base_url)

      Rails.logger.info "Checking ComfyUI availability at #{base_url}..."

      begin
        http = Net::HTTP.new(base_uri.host, base_uri.port)
        http.open_timeout = 3
        http.read_timeout = 3

        # Check if ComfyUI is up (simple GET to root)
        response = http.get("/")
        unless response.code.to_i < 500
          raise StandardError, "ComfyUI API returned status #{response.code}"
        end

        Rails.logger.info "✓ ComfyUI is available at #{base_url}"
      rescue Errno::ECONNREFUSED, Errno::EHOSTUNREACH, SocketError => e
        Rails.logger.error "Cannot connect to ComfyUI at #{base_url}: #{e.message}"
        raise StandardError, "ComfyUI service is not available at #{base_url}. Please ensure ComfyUI is running."
      rescue Net::ReadTimeout, Net::OpenTimeout, Timeout::Error => e
        Rails.logger.error "Timeout connecting to ComfyUI: #{e.message}"
        raise StandardError, "Timeout connecting to ComfyUI service. Please check if ComfyUI is running."
      rescue StandardError => e
        raise e if e.message.include?("ComfyUI")
        Rails.logger.error "Error checking ComfyUI availability: #{e.message}"
        raise StandardError, "Failed to verify ComfyUI availability: #{e.message}"
      end
    end

    def upload_image(blob)
      # Upload image to ComfyUI and return filename
      base_uri = URI(base_url)
      http = Net::HTTP.new(base_uri.host, base_uri.port)
      http.open_timeout = 10
      http.read_timeout = 10

      image_data = blob.download
      # Force binary encoding to ensure image data is handled correctly
      image_data.force_encoding("BINARY") if image_data.respond_to?(:force_encoding)
      Rails.logger.info "Uploading image to ComfyUI: blob_id=#{blob.id}, size=#{image_data.bytesize} bytes, content_type=#{blob.content_type}"

      extension = blob.filename.extension.presence || "jpg"
      filename = "#{SecureRandom.hex(8)}.#{extension}"

      request = Net::HTTP::Post.new("/upload/image")
      form_data = [
        [ "image", image_data, { filename: filename, content_type: blob.content_type } ]
      ]
      request.set_form(form_data, "multipart/form-data")

      response = http.request(request)

      unless response.code == "200"
        raise StandardError, "ComfyUI image upload returned status #{response.code}: #{response.body}"
      end

      parsed = JSON.parse(response.body)
      uploaded_filename = parsed["name"] || filename

      Rails.logger.info "Image uploaded to ComfyUI: #{uploaded_filename}"
      uploaded_filename
    rescue JSON::ParserError => e
      Rails.logger.error "Failed to parse ComfyUI upload response: #{e.message}"
      raise StandardError, "Invalid response from ComfyUI upload API"
    end

